request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?elem ?type ?name ?loopType WHERE {
  ?elem tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo <https://www.teamingai-project.eu/kg/model/sid_628f8db4_6e66_4dbc_bf51_0a06087845fd> .
  {
    ?elem a bboExt:ParallelGateway .
    BIND("ParallelGateway" AS ?type)
  } UNION {
    ?elem a bboExt:ChoreographyTask .
    ?elem bboExt:loopType ?loopType .
    FILTER(?loopType = "MultiInstanceParallel")
    BIND("MultiInstanceParallelTask" AS ?type)
  }
  OPTIONAL { ?elem bbo:name ?name . }
}
LIMIT 25
